import { ChatFlowCallbackHandler } from 'flowise/dist/src/CallbackHandler';

class DriftCallbackHandler extends ChatFlowCallbackHandler {
  constructor() {
    super();
    this.driftAlerts = [];
  }

  async handleLLMEnd(output: any) {
    const content = output.generations[0][0].text;

    // Detect JSON malformation
    try {
      JSON.parse(content);
    } catch (e) {
      this.driftAlerts.push({
        type: 'llm_chain_drift',
        message: 'Malformed JSON output',
        confidence: 0,
        timestamp: new Date().toISOString()
      });
    }

    // Detect low confidence
    if (output.llmOutput?.tokenUsage?.totalTokens > 100 && content.length < 20) {
      this.driftAlerts.push({
        type: 'llm_short_output',
        message: 'Suspiciously short output',
        confidence: 0.3,
        timestamp: new Date().toISOString()
      });
    }
  }

  getAlerts() {
    return this.driftAlerts;
  }
}

export default DriftCallbackHandler;

import { DocumentLoaderCallbackHandler } from 'flowise/dist/src/CallbackHandler';

class VectorDriftHandler extends DocumentLoaderCallbackHandler {
  constructor() {
    super();
    this.relevanceIssues = [];
  }

  handleRetrieverEnd(documents: any[]) {
    documents.forEach((doc, index) => {
      const metadata = doc.metadata || {};
      const similarity = metadata.similarityScore || 0;

      if (similarity < 0.7) {
        this.relevanceIssues.push({
          type: 'low_relevance_docs',
          documentIndex: index,
          similarity: similarity,
          contentPreview: doc.pageContent?.substring(0, 100),
          timestamp: new Date().toISOString()
        });
      }
    });
  }

  hasDrift() {
    return this.relevanceIssues.length > 0;
  }
}

export default VectorDriftHandler;

class ToolDriftHandler {
  constructor() {
    this.toolFailures = [];
  }

  handleToolOutput(toolName: string, output: any) {
    const isFailure = !output || 
      (typeof output === 'string' && output.trim().length === 0) ||
      (typeof output === 'object' && Object.keys(output).length === 0);

    if (isFailure) {
      this.toolFailures.push({
        type: 'custom_tool_failure',
        toolName,
        output: output,
        expectedNonEmpty: true,
        timestamp: new Date().toISOString()
      });
    }
  }

  failureRate() {
    return this.toolFailures.length;
  }
}

// Usage in Flowise Custom Tool node
const driftHandler = new ToolDriftHandler();

// In your tool function:
export async function myCustomTool(input: any) {
  const result = await processInput(input);
  driftHandler.handleToolOutput('myCustomTool', result);
  return result;
}

