// Custom Validator Node for Flowise
const LLMOutputValidator = {
  name: 'LLM Output Validator',
  async invoke(input: any, config: any) {
    const content = input.content || input.text;

    // JSON Validation
    let isValidJSON = false;
    try {
      JSON.parse(content);
      isValidJSON = true;
    } catch (e) {
      // Return validation error
      return {
        content: `Validation failed: Invalid JSON output`,
        metadata: { valid: false, error: 'JSON_PARSE_ERROR' }
      };
    }

    // Length validation
    if (content.length < 50) {
      return {
        content: `Validation failed: Output too short (${content.length} chars)`,
        metadata: { valid: false, error: 'SHORT_OUTPUT' }
      };
    }

    return {
      content,
      metadata: { valid: true }
    };
  }
};

export default LLMOutputValidator;

// Vector Store Retriever with filtering
const FilteredRetrieverNode = {
  name: 'Filtered Vector Retriever',
  MIN_SIMILARITY: 0.75,

  async invoke(input: any, config: any) {
    const { documents } = await config.retriever.invoke(input);

    const filteredDocs = documents.filter(doc => {
      const score = doc.metadata?.similarityScore || 0;
      return score >= this.MIN_SIMILARITY;
    });

    if (filteredDocs.length === 0) {
      return {
        documents: [],
        metadata: {
          warning: 'No relevant documents found',
          originalCount: documents.length,
          filteredCount: 0
        }
      };
    }

    return {
      documents: filteredDocs,
      metadata: {
        filtered: true,
        retained: filteredDocs.length,
        threshold: this.MIN_SIMILARITY
      }
    };
  }
};

export default FilteredRetrieverNode;

// Enhanced Memory Node for Multi-Agent Flow
const PersistentContextNode = {
  name: 'Persistent Context Handler',

  async invoke(input: any, config: any) {
    const sessionId = input.sessionId || 'default';
    const currentContext = input.context || {};

    // Merge incoming context with session state
    const fullContext = {
      ...this.getSessionState(sessionId),
      ...currentContext,
      timestamp: Date.now(),
      sessionId
    };

    // Update session state
    this.setSessionState(sessionId, fullContext);

    return {
      ...input,
      context: fullContext,
      metadata: {
        contextSize: Object.keys(fullContext).length,
        sessionMaintained: true
      }
    };
  },

  sessionStates: new Map(),

  getSessionState(sessionId: string) {
    return this.sessionStates.get(sessionId) || {};
  },

  setSessionState(sessionId: string, state: any) {
    this.sessionStates.set(sessionId, state);
  }
};

export default PersistentContextNode;

