import { Vex } from '@vex_dev/sdk';

// Flowise Server Configuration (server/src/index.ts)
import Flowise from 'flowise';

const app = Flowise.createApp();

// Initialize Vex with Flowise integration
const vex = new Vex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
  framework: 'flowise',
  autoInstrument: true,
  driftMonitors: {
    llmChain: {
      jsonValidation: true,
      minOutputLength: 50,
      confidenceThreshold: 0.8
    },
    vectorRetrieval: {
      minSimilarity: 0.75,
      maxIrrelevantDocs: 2
    },
    customTools: {
      detectSilentFailures: true,
      requireNonEmpty: true
    },
    agentHandoffs: {
      contextRetention: true,
      maxContextLoss: 0.1
    }
  }
});

// Single line integration
app.use(vex.flowiseMiddleware());

app.listen(3000);

// Vex auto-generates remediation flows
const remediationFlow = await vex.createRemediationFlow({
  name: 'flowise-drift-fixer',
  triggers: ['llm_drift', 'retrieval_drift', 'tool_failure'],
  actions: [
    'deploy_validator_node',
    'adjust_retrieval_threshold',
    'restart_agent_session'
  ]
});
